from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

class OKRLevel(Enum):
    COMPANY  = "company"
    PROGRAM  = "program"
    TEAM     = "team"

class OKRStatus(Enum):
    ON_TRACK   = "on_track"    # current value on pace for target
    AT_RISK    = "at_risk"     # lagging; needs attention
    OFF_TRACK  = "off_track"   # significantly behind; escalation needed
    ACHIEVED   = "achieved"    # target hit
    MISSED     = "missed"      # quarter ended below target

@dataclass
class KeyResult:
    kr_id: str
    description: str
    target_value: float
    current_value: float
    unit: str              # e.g. "%", "s", "$", "count"
    data_source: str       # where to pull current_value from
    owner_role: str

    @property
    def progress_pct(self) -> float:
        if self.target_value == 0:
            return 1.0 if self.current_value == 0 else 0.0
        return min(self.current_value / self.target_value, 1.0)

    def status(self, weeks_elapsed: int, quarter_weeks: int = 13) -> OKRStatus:
        time_pct = weeks_elapsed / quarter_weeks
        expected_progress = time_pct  # linear expectation
        if self.progress_pct >= 1.0:
            return OKRStatus.ACHIEVED
        gap = expected_progress - self.progress_pct
        if gap <= 0.05:
            return OKRStatus.ON_TRACK
        if gap <= 0.20:
            return OKRStatus.AT_RISK
        return OKRStatus.OFF_TRACK

@dataclass
class Objective:
    obj_id: str
    level: OKRLevel
    title: str
    quarter: str                        # e.g. "2026-Q3"
    parent_obj_ids: list[str] = field(default_factory=list)  # empty at company level
    key_results: list[KeyResult] = field(default_factory=list)
    owner_role: str = ""
    team_name: str = ""

    def overall_progress_pct(self) -> float:
        if not self.key_results:
            return 0.0
        return sum(kr.progress_pct for kr in self.key_results) / len(self.key_results)

from collections import defaultdict

@dataclass
class OKRCascade:
    objectives: list[Objective]

    def _by_id(self) -> dict[str, Objective]:
        return {o.obj_id: o for o in self.objectives}

    def check_alignment(self) -> list[str]:
        """
        Return list of issues: orphan objectives, team KRs with no program parent, etc.
        """
    issues = []
    by_id = self._by_id()

    for obj in self.objectives:
        if obj.level == OKRLevel.TEAM:
            if not obj.parent_obj_ids:
                issues.append(f"ORPHAN: team objective '{obj.obj_id}' has no parent program objective")
            else:
                for pid in obj.parent_obj_ids:
                    if pid not in by_id:
                        issues.append(f"BROKEN_LINK: '{obj.obj_id}' references missing parent '{pid}'")
                    elif by_id[pid].level != OKRLevel.PROGRAM:
                        issues.append(f"WRONG_LEVEL: '{obj.obj_id}' should link to PROGRAM level, not {by_id[pid].level}")

        if obj.level == OKRLevel.PROGRAM:
            if not obj.parent_obj_ids:
                issues.append(f"ORPHAN: program objective '{obj.obj_id}' has no parent company objective")

        if not obj.key_results:
            issues.append(f"NO_KRS: objective '{obj.obj_id}' has no key results")

    return issues

    def cascade_progress(self) -> dict[str, float]:
        """Return overall progress % for each objective, aggregated from KRs."""
        return {o.obj_id: round(o.overall_progress_pct() * 100, 1) for o in self.objectives}

from datetime import date

@dataclass
class OKRCheckIn:
    cascade_quarter: str
    check_in_date: date
    week_number: int
    kr_updates: list[dict]   # [{"kr_id": ..., "current_value": ..., "notes": ...}]

def apply_check_in(cascade: OKRCascade, check_in: OKRCheckIn) -> list[str]:
    """
    Update current_value for each KR; return list of status changes (for notifications).
    """
    by_kr: dict[str, KeyResult] = {}
    for obj in cascade.objectives:
        for kr in obj.key_results:
            by_kr[kr.kr_id] = kr

    status_changes = []
    for update in check_in.kr_updates:
        kr = by_kr.get(update["kr_id"])
        if kr is None:
            continue
        old_status = kr.status(check_in.week_number)
        kr.current_value = update["current_value"]
        new_status = kr.status(check_in.week_number)
        if old_status != new_status:
            status_changes.append(
                f"{kr.kr_id}: {old_status.value} → {new_status.value}"
            )
    return status_changes

def score_quarter(cascade: OKRCascade) -> dict[str, dict]:
    """
    Score each objective at quarter end. Returns per-objective summary.
    """
    results = {}
    for obj in cascade.objectives:
        kr_scores = []
        for kr in obj.key_results:
            score = min(kr.current_value / kr.target_value, 1.0) if kr.target_value else 0.0
            kr_scores.append({
                "kr_id": kr.kr_id,
                "score": round(score, 2),
                "current": kr.current_value,
                "target": kr.target_value,
                "unit": kr.unit,
                "grade": "green" if score >= 0.7 else "amber" if score >= 0.4 else "red",
            })
        obj_score = sum(k["score"] for k in kr_scores) / len(kr_scores) if kr_scores else 0.0
        results[obj.obj_id] = {
            "title": obj.title,
            "level": obj.level.value,
            "objective_score": round(obj_score, 2),
            "grade": "green" if obj_score >= 0.7 else "amber" if obj_score >= 0.4 else "red",
            "key_results": kr_scores,
        }
    return results

@dataclass
class KRDependency:
    dependent_kr_id: str    # this KR cannot progress until...
    depends_on_kr_id: str   # ...this KR reaches a minimum threshold
    minimum_progress: float # e.g. 0.5 means 'at least 50 % of depends_on_kr must be done'
    dependency_type: str    # "blocking" | "enabling" | "informing"

def find_blocking_dependencies(
    cascade: OKRCascade,
    dependencies: list[KRDependency],
    weeks_elapsed: int,
) -> list[str]:
    """
    Return list of alert strings for KRs that are blocked by lagging upstream KRs.
    """
    kr_by_id: dict[str, KeyResult] = {}
    for obj in cascade.objectives:
        for kr in obj.key_results:
            kr_by_id[kr.kr_id] = kr

    alerts = []
    for dep in dependencies:
        if dep.dependency_type != "blocking":
            continue
        upstream = kr_by_id.get(dep.depends_on_kr_id)
        downstream = kr_by_id.get(dep.dependent_kr_id)
        if upstream is None or downstream is None:
            continue
        if upstream.progress_pct < dep.minimum_progress:
            upstream_status = upstream.status(weeks_elapsed)
            alerts.append(
                f"BLOCKED: '{dep.dependent_kr_id}' waiting for "
                f"'{dep.depends_on_kr_id}' ({upstream.progress_pct*100:.0f}% / "
                f"{dep.minimum_progress*100:.0f}% needed, status: {upstream_status.value})"
            )
    return alerts

@dataclass
class ProjectKRContribution:
    project_id: str     # e.g. "GEN-A1F2" from the intake portal
    kr_id: str
    expected_contribution: float   # what fraction of the KR target this project covers
    contribution_type: str         # "direct" | "enabling" | "partial"

def validate_portfolio_okr_coverage(
    committed_projects: list[str],
    contributions: list[ProjectKRContribution],
    cascade: OKRCascade,
) -> dict[str, list[str]]:
    """
    Return mapping of KR → projects that cover it.
    Flag KRs with no project contributions (delivery risk).
    """
    kr_coverage: dict[str, list[str]] = {}
    for c in contributions:
        if c.project_id in committed_projects:
            kr_coverage.setdefault(c.kr_id, []).append(c.project_id)

    uncovered: list[str] = []
    for obj in cascade.objectives:
        for kr in obj.key_results:
            if kr.kr_id not in kr_coverage:
                uncovered.append(kr.kr_id)

    return {"covered": kr_coverage, "uncovered_krs": uncovered}
